# Structured input validation using Pydantic + custom domain rules
# Pattern for applications that receive structured inputs (not raw chat)

from dataclasses import dataclass, field
from typing import Any, Dict, List, Optional
import re

@dataclass
class ValidationError:
    field: str
    message: str
    severity: str  # "block" | "warn"

@dataclass
class InputValidationResult:
    valid: bool
    errors: List[ValidationError] = field(default_factory=list)
    sanitized: Optional[Dict[str, Any]] = None

def sanitize_text(text: str, max_length: int = 4000) -> str:
    """Remove null bytes, normalize whitespace, truncate."""
    text = text.replace('\x00', '')          # null bytes
    text = re.sub(r'\s+', ' ', text).strip() # normalize whitespace
    return text[:max_length]                  # hard truncate

def validate_customer_query(raw_input: Dict[str, Any]) -> InputValidationResult:
    """
    Validates and sanitizes a structured customer support query
    before it reaches the language model.
    """
    errors: List[ValidationError] = []
    sanitized: Dict[str, Any] = {}

    # Required field: message
    message = raw_input.get("message", "")
    if not message or not message.strip():
        errors.append(ValidationError("message", "Message cannot be empty", "block"))
    else:
        sanitized["message"] = sanitize_text(str(message))

        # Length gate
        if len(sanitized["message"]) < 3:
            errors.append(ValidationError("message", "Message too short", "block"))

        # Content check: no null-byte injection
        if '\x00' in message:
            errors.append(ValidationError("message", "Invalid characters detected", "block"))

    # Optional field: customer_id (must be alphanumeric)
    if "customer_id" in raw_input:
        cid = str(raw_input["customer_id"])
        if not re.fullmatch(r'[A-Z0-9\-]{4,32}', cid, re.IGNORECASE):
            errors.append(ValidationError(
                "customer_id", "customer_id format invalid", "warn"
            ))
        else:
            sanitized["customer_id"] = cid.upper()

    # Optional field: topic (allowlist)
    ALLOWED_TOPICS = {"billing", "shipping", "returns", "technical", "account", "other"}
    if "topic" in raw_input:
        topic = str(raw_input.get("topic", "")).lower()
        if topic not in ALLOWED_TOPICS:
            errors.append(ValidationError(
                "topic",
                f"topic must be one of {sorted(ALLOWED_TOPICS)}",
                "warn"
            ))
            sanitized["topic"] = "other"  # default to safe value
        else:
            sanitized["topic"] = topic

    blocking_errors = [e for e in errors if e.severity == "block"]
    return InputValidationResult(
        valid=len(blocking_errors) == 0,
        errors=errors,
        sanitized=sanitized if len(blocking_errors) == 0 else None,
    )

# Test cases
test_inputs = [
    {"message": "My order is late", "customer_id": "CUST-1234", "topic": "shipping"},
    {"message": "", "customer_id": "CUST-1234"},
    {"message": "Refund my order", "customer_id": "bad id!", "topic": "returns"},
    {"message": "A" * 5000, "topic": "billing"},         # over-length
    {"message": "Help\x00me", "customer_id": "X-99"},    # null byte injection
]

for inp in test_inputs:
    result = validate_customer_query(inp)
    print(f"Input: message={str(inp.get('message',''))[:30]!r}...")
    print(f"  Valid: {result.valid}")
    if result.errors:
        for e in result.errors:
            print(f"  [{e.severity.upper()}] {e.field}: {e.message}")
    if result.sanitized:
        msg = result.sanitized.get('message','')
        print(f"  Sanitized message length: {len(msg)}")
    print()
